#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

typedef struct Edge {int to; struct Edge* next;} Edge;

#define MAXN 100000

Edge* adj[MAXN + 5];
int degree[MAXN + 5];
bool found;

void add_edge(int u, int v) {
    Edge* e = (Edge*)malloc(sizeof(Edge));
    e->to = v; e->next = adj[u]; adj[u] = e;
}

void dfs(int node, int parent, long long sum, long long target) {
    sum += node;
    for (Edge* e = adj[node]; e; e = e->next) {
        if (e->to != parent) dfs(e->to, node, sum, target);
    }
    if (parent != -1 && degree[node] == 1) {
        if (sum == target) found = true;
    }
    // sum backtrack not needed because sum is passed by value
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n; long long target; scanf("%d %lld", &n, &target);
        for (int i = 1; i <= n; ++i) {adj[i] = NULL; degree[i] = 0;}
        for (int i = 0; i < n-1; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            degree[u]++; degree[v]++;
            add_edge(u, v);
            add_edge(v, u);
        }
        found = false;
        dfs(1, -1, 0, target);
        printf("%s\n", found ? "YES" : "NO");
        // free memory (optional for contest)
        for (int i = 1; i <= n; ++i) {
            Edge* e = adj[i];
            while (e) {Edge* nxt = e->next; free(e); e = nxt;}
        }
    }
    return 0;
}

