const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const n = data[idx++];
  const target = data[idx++];
  const adj = Array.from({length: n + 1}, () => []);
  const degree = new Array(n + 1).fill(0);
  for (let i = 0; i < n - 1; i++) {
    const u = data[idx++];
    const v = data[idx++];
    adj[u].push(v);
    adj[v].push(u);
    degree[u]++; degree[v]++;
  }
  let found = false;
  function dfs(node, parent, sum) {
    sum += node;
    for (const nb of adj[node]) {
      if (nb !== parent) dfs(nb, node, sum);
    }
    if (parent !== -1 && degree[node] === 1 && sum === target) {
      found = true;
    }
  }
  dfs(1, -1, 0);
  outputs.push(found ? 'YES' : 'NO');
}
